# Day 167: FastAPI: Setup, Uvicorn, and Your First Endpoint
# FastAPI: First Endpoint
# Save as main.py, run: uvicorn main:app --reload

from fastapi import FastAPI

app = FastAPI(title="ML API", version="1.0")

@app.get("/")
def root():
    return {"message": "ML API is running!", "status": "healthy"}

@app.get("/predict/{item_id}")
def predict(item_id: int, q: str = None):
    return {"item_id": item_id, "query": q, "prediction": 0.87}

@app.post("/train")
def train(data: dict):
    return {"status": "training started", "samples": len(data.get("features", []))}

print("Save as main.py")
print("Run: uvicorn main:app --reload")
print("Open: http://localhost:8000/docs")
